<?php
namespace Tests\Feature;
use App\Actions\CreateServiceEntryAction;use App\Models\{Project,User};use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class ServiceEntryTest extends TestCase{use RefreshDatabase; private function project(): Project{return Project::create(['user_id'=>User::factory()->create()->id,'name'=>'Дом']);} public function test_hourly_unit_and_fixed_totals(): void{$p=$this->project();$a=app(CreateServiceEntryAction::class);$this->assertEquals(3000,$a->execute(['project_id'=>$p->id,'date'=>'2026-05-10','name'=>'Работа','pricing_type'=>'hourly','hours'=>5,'hourly_rate'=>600,'payment_status'=>'paid'])->total_amount);$this->assertEquals(4500,$a->execute(['project_id'=>$p->id,'date'=>'2026-05-10','name'=>'Кладка','pricing_type'=>'unit','quantity'=>3,'unit_price'=>1500,'payment_status'=>'paid'])->total_amount);$this->assertEquals(7000,$a->execute(['project_id'=>$p->id,'date'=>'2026-05-10','name'=>'Доставка','pricing_type'=>'fixed','total_amount'=>7000,'payment_status'=>'paid'])->total_amount);}}
